                    { gramType: "quiz", q: "ネットの掲示板には、多数の（___________）があった。", ans: "書き込み", w1: "書き取り", w2: "差し取り", w3: "差し込み", explain: "書き取り（かきとり）: chép chính tả\n差し取り（さしとり）: từ sai\n書き込み（かきこみ）: bài đăng\n差し込み（さしこみ）: chèn vào\nDịch: Trên diễn đàn mạng có rất nhiều bài đăng.", count: 0 },
                    { gramType: "quiz", q: "アンケートの回答欄が足りなかったので、余白に（___________）。", ans: "書き込みました", w1: "差し込みました", w2: "引き込みました", w3: "駆け引きました", explain: "書き込みました（かきこみました）: đã viết thêm vào\n差し込みました（さしこみました）: chèn vào\n引き込みました（ひきこみました）: kéo vào\n駆け引きました（かけひきました）: mặc cả\nDịch: Vì chỗ trả lời khảo sát không đủ nên tôi đã viết thêm vào phần trống.", count: 0 },
                    { gramType: "quiz", q: "契約書だから、（___________）で送りましょう。", ans: "書留", w1: "解留", w2: "会留", w3: "回留", explain: "解留（かいりゅう）: từ sai\n会留（かいりゅう）: từ sai\n書留（かきとめ）: thư bảo đảm\n回留（かいりゅう）: từ sai\nDịch: Vì là hợp đồng nên hãy gửi bằng thư bảo đảm.", count: 0 },
                    { gramType: "quiz", q: "会議で出たアイデアを（___________）おいて、あとでPCのファイルに整理した。", ans: "書き留めて", w1: "引き込んで", w2: "書き取って", w3: "引き留めて", explain: "引き込んで（ひきこんで）: kéo vào\n書き取って（かきとって）: ghi chép lại\n書き留めて（かきとめて）: ghi chú lại\n引き留めて（ひきとめて）: giữ lại\nDịch: Tôi ghi chú lại các ý tưởng đưa ra trong cuộc họp rồi sau đó sắp xếp vào file trên máy tính.", count: 0 },
                    { gramType: "quiz", q: "よくランチに行くあの店、今週（___________）で閉店だって。", ans: "限り", w1: "欠き", w2: "締め", w3: "解き", explain: "限り（かぎり）: đến hết\n欠き（かき）: thiếu\n締め（しめ）: đóng\n解き（とき）: tháo ra\nDịch: Quán hay đi ăn trưa đó sẽ đóng cửa từ tuần này.", count: 0 },
                    { gramType: "quiz", q: "社内の新人事は、今朝、（___________）部署に通知された。", ans: "各", w1: "挌", w2: "格", w3: "客", explain: "挌（かく）: từ sai\n格（かく）: tiêu chuẩn\n各（かく）: mỗi\n客（きゃく）: khách\nDịch: Nhân sự mới trong công ty đã được thông báo tới các bộ phận vào sáng nay.", count: 0 },
                    { gramType: "quiz", q: "関係（___________）のご協力をお願い申し上げます。", ans: "各位", w1: "格位", w2: "各地", w3: "格地", explain: "各位（かくい）: quý vị\n格位（かくい）: từ sai\n各地（かくち）: các địa phương\n格地（かくち）: từ sai\nDịch: Kính mong sự hợp tác của các bên liên quan.", count: 0 },
                    { gramType: "quiz", q: "本日午後、大型台風接近のため、（___________）の判断で業務を切り上げ、安全に帰宅すること。", ans: "各自", w1: "各市", w2: "格市", w3: "格自", explain: "各市（かくし）: mỗi thành phố\n各自（かくじ）: mỗi người\n格市（かくし）: từ sai\n格自（かくじ）: từ sai\nDịch: Chiều nay do bão lớn đến gần, mỗi người hãy tự quyết định kết thúc công việc sớm và về nhà an toàn.", count: 0 },
                    { gramType: "quiz", q: "（___________）手続きに関する書類は、新入社員に送付済みです。", ans: "各種", w1: "格充", w2: "各充", w3: "格種", explain: "格充（かくじゅう）: từ sai\n各充（かくじゅう）: từ sai\n各種（かくしゅ）: các loại\n格種（かくしゅ）: từ sai\nDịch: Các tài liệu liên quan đến các thủ tục khác nhau đã được gửi cho nhân viên mới.", count: 0 },
                    { gramType: "quiz", q: "A社は、個人向けサービスをさらに（___________）していく方針だ。", ans: "拡充", w1: "建設", w2: "発揮", w3: "改発", explain: "拡充（かくじゅう）: mở rộng, tăng cường\n建設（けんせつ）: xây dựng\n発揮（はっき）: phát huy\n改発（かいはつ）: từ sai\nDịch: Công ty A có phương châm tiếp tục mở rộng dịch vụ dành cho cá nhân.", count: 0 },
                    { gramType: "quiz", q: "企業人として、（___________）の役割をきちんと果たすことが大切だ。", ans: "各人", w1: "各市", w2: "各節", w3: "各地", explain: "各市（かくし）: mỗi thành phố\n各人（かくじん）: mỗi người\n各節（かくせつ）: mỗi đoạn\n各地（かくち）:各 địa phương\nDịch: Là một người làm trong doanh nghiệp, điều quan trọng là mỗi người phải hoàn thành tốt vai trò của mình.", count: 0 }
