                    { gramType: "quiz", q: "パソコンを買ったら、自分が使いやすいように、（___________）するといい。", ans: "カスタマイズ", w1: "コンチョゴム", w2: "カスタム", w3: "クレーム", explain: "カスタマイズ: tùy chỉnh\nコンチョゴム: từ sai\nカスタム: custom\nクレーム: khiếu nại\nDịch: Sau khi mua máy tính thì nên tùy chỉnh sao cho bản thân dễ sử dụng.", count: 0 },
                    { gramType: "quiz", q: "Thuế", ans: "課税", w1: "課題", w2: "課説", w3: "課州", explain: "課税（かぜい）: thuế má\n課題（かだい）: bài tập, vấn đề\n課説（かせつ）: từ sai\n課州（かしゅう）: từ sai\nDịch: Thuế.", count: 0 },
                    { gramType: "quiz", q: "Công trình tạm thời", ans: "仮設", w1: "架設", w2: "仮説", w3: "加設", explain: "仮設（かせつ）: công trình tạm thời\n架設（かせつ）: lắp dựng\n仮説（かせつ）: giả thuyết\n加設（かせつ）: lắp thêm\nDịch: Công trình tạm thời.", count: 0 }
