                    { gramType: "quiz", q: "新作のゲームソフトのタイトルは、まだ（___________）ですが【クイズで世界一周】を考えています。", ans: "仮題", w1: "反題", w2: "反代", w3: "仮代", explain: "仮題（かだい）: tiêu đề tạm thời\n反題（はんだい）: từ sai\n反代（はんだい）: từ sai\n仮代（かだい）: từ sai\nDịch: Tiêu đề của game mới hiện vẫn là tạm thời, đang nghĩ đến 'Du lịch vòng quanh thế giới bằng quiz'.", count: 0 },
                    { gramType: "quiz", q: "新モデルのS-50が出たので、（___________）のS-30は2割引になっている。", ans: "型落ち", w1: "式落ち", w2: "刑落ち", w3: "新落ち", explain: "型落ち（かたおち）: mẫu cũ, đời cũ\n式落ち（しきおち）: từ sai\n刑落ち（けいおち）: từ sai\n新落ち（しんおち）: từ sai\nDịch: Vì mẫu mới S-50 đã ra mắt nên mẫu cũ S-30 được giảm giá 20%.", count: 0 },
                    { gramType: "quiz", q: "出席者リストの田中さんの（___________）が、名刺と違っている。", ans: "肩書", w1: "皮書", w2: "腹書", w3: "顔書", explain: "肩書（かたがき）: chức danh\n皮書（ひしょ）: từ sai\n腹書（ふくしょ）: từ sai\n顔書（がおがき）: từ sai\nDịch: Chức danh của anh Tanaka trong danh sách người tham dự khác với trên danh thiếp.", count: 0 },
                    { gramType: "quiz", q: "簡単なアンケートの集計だけど、これだけ量が多いと、（___________）ではできない。", ans: "片手間", w1: "付手間", w2: "平手間", w3: "信手間", explain: "片手間（かたてま）: làm tranh thủ, làm tay trái\n付手間（つきてま）: từ sai\n平手間（ひらてま）: từ sai\n信手間（しんてま）: từ sai\nDịch: Dù chỉ là tổng hợp khảo sát đơn giản nhưng nhiều thế này thì không thể làm qua loa được.", count: 0 },
                    { gramType: "quiz", q: "商品の裏側に、（___________）が記載されたラベルが貼ってあります。", ans: "型番", w1: "型席", w2: "型毛", w3: "型尻", explain: "型番（かたばん）: mã sản phẩm, số model\n型席（かたせき）: từ sai\n型毛（かたげ）: từ sai\n型尻（かたじり）: từ sai\nDịch: Mặt sau sản phẩm có dán nhãn ghi mã model.", count: 0 },
                    { gramType: "quiz", q: "Một bên", ans: "片方", w1: "片型", w2: "型方", w3: "兵方", explain: "片方（かたほう）: một bên\n片型（かたがた）: từ sai\n型方（かたほう）: từ sai\n兵方（へいほう）: từ sai\nDịch: Một bên.", count: 0 },
                    { gramType: "quiz", q: "昨日の役員会議で、ようやく来年度の事業方針が（___________）。", ans: "固まった", w1: "締めた", w2: "仕えた", w3: "触った", explain: "固まった（かたまった）: đã được thống nhất, cố định\n締めた（しめた）: siết chặt\n仕えた（つかえた）: phục vụ\n触った（さわった）: chạm vào\nDịch: Trong cuộc họp ban giám đốc hôm qua, cuối cùng phương châm kinh doanh năm sau cũng đã được thống nhất.", count: 0 },
                    { gramType: "quiz", q: "A社は、新宿にあるビルを売却する方針を（___________）。", ans: "固めた", w1: "極めた", w2: "仕えた", w3: "絞めた", explain: "固めた（かためた）: quyết định chắc chắn\n極めた（きわめた）: làm đến mức cao nhất\n仕えた（つかえた）: phục vụ\n絞めた（しめた）: siết cổ\nDịch: Công ty A đã quyết định chính sách bán tòa nhà ở Shinjuku.", count: 0 },
                    { gramType: "quiz", q: "この商品は、最新の（___________）にも載っています。", ans: "カタログ", w1: "カレンダー", w2: "カシージャス", w3: "カテゴリー", explain: "カタログ: catalogue\nカレンダー: lịch\nカシージャス: tên riêng\nカテゴリー: danh mục\nDịch: Sản phẩm này cũng được đăng trong catalogue mới nhất.", count: 0 },
                    { gramType: "quiz", q: "Trưởng bộ phận", ans: "課長", w1: "店長", w2: "社長", w3: "延長", explain: "課長（かちょう）: trưởng bộ phận\n店長（てんちょう）: quản lý cửa hàng\n社長（しゃちょう）: giám đốc công ty\n延長（えんちょう）: gia hạn\nDịch: Trưởng bộ phận.", count: 0 },
                    { gramType: "quiz", q: "スペースがないから、この部分は（___________）するしかない。", ans: "割愛", w1: "割合", w2: "割引", w3: "割込", explain: "割愛（かつあい）: lược bỏ\n割合（わりあい）: tỷ lệ\n割引（わりびき）: giảm giá\n割込（わりこみ）: chen vào\nDịch: Vì không có chỗ nên chỉ còn cách lược bỏ phần này.", count: 0 },
                    { gramType: "quiz", q: "来月A社が発表するソフトは、今までにない（___________）な商品だと言われている。", ans: "画期的", w1: "計画的", w2: "結束的", w3: "機体的", explain: "画期的（かっきてき）: mang tính đột phá\n計画的（けいかくてき）: có kế hoạch\n結束的（けっそくてき）: có tính đoàn kết\n機体的（きたいてき）: từ sai\nDịch: Phần mềm mà công ty A sẽ công bố tháng sau được cho là sản phẩm mang tính đột phá chưa từng có.", count: 0 },
                    { gramType: "quiz", q: "Dấu ngoặc", ans: "括弧", w1: "確固", w2: "拝啓", w3: "御中", explain: "括弧（かっこ）: dấu ngoặc\n確固（かっこ）: vững chắc\n拝啓（はいけい）: kính gửi\n御中（おんちゅう）: kính gửi\nDịch: Dấu ngoặc.", count: 0 },
                    { gramType: "quiz", q: "商店街の（___________）のために、さまざまな集客イベントが予定されている。", ans: "活性化", w1: "生活差", w2: "生活識", w3: "生活課", explain: "活性化（かっせいか）: vực dậy, kích hoạt, làm sôi động\n生活差（せいかつさ）: từ sai\n生活識（せいかつしき）: từ sai\n生活課（せいかつか）: phòng đời sống\nDịch: Nhiều sự kiện thu hút khách đang được lên kế hoạch để làm sôi động khu phố mua sắm.", count: 0 },
                    { gramType: "quiz", q: "Dao rọc giấy, máy cắt", ans: "カッター", w1: "カシージャス", w2: "フナショク", w3: "カソード", explain: "カッター: dao cắt, dao rọc giấy\nカシージャス: tên riêng\nフナショク: từ sai\nカソード: cathode\nDịch: Dao rọc giấy, máy cắt.", count: 0 },
                    { gramType: "quiz", q: "この辺は（___________）を知った場所だから、どこでも案内できます。", ans: "勝手", w1: "活気", w2: "失敬", w3: "根系", explain: "勝手（かって）: quen thuộc, tiện\n活気（かっき）: sự nhộn nhịp\n失敬（しっけい）: thất lễ\n根系（こんけい）: hệ rễ\nDịch: Vì tôi rất quen khu này nên có thể hướng dẫn đi bất cứ đâu.", count: 0 },
                    { gramType: "quiz", q: "A社とB社は、（___________）により業界シェアトップの企業となった。", ans: "合併", w1: "合計", w2: "合格", w3: "合板", explain: "合併（がっぺい）: sáp nhập\n合計（ごうけい）: tổng cộng\n合格（ごうかく）: đỗ\n合板（ごうはん）: ván ép\nDịch: Công ty A và B đã trở thành doanh nghiệp đứng đầu thị phần ngành nhờ việc sáp nhập.", count: 0 },
                    { gramType: "quiz", q: "環境のためにも、資源の有効（___________）を心がけなければいけない。", ans: "活用", w1: "活気", w2: "活的", w3: "活伸", explain: "活用（かつよう）: sử dụng hiệu quả\n活気（かっき）: sự sôi động\n活的（かつてき）: từ sai\n活伸（かつしん）: từ sai\nDịch: Vì môi trường, chúng ta phải chú ý sử dụng hiệu quả tài nguyên.", count: 0 },
                    { gramType: "quiz", q: "参加者が100人を超えるという（___________）のもとに、大ホールを借りることにしました。", ans: "仮定", w1: "過程", w2: "課程", w3: "新訂", explain: "仮定（かてい）: giả định\n過程（かてい）: quá trình\n課程（かてい）: chương trình học\n新訂（しんてい）: tái bản mới\nDịch: Dựa trên giả định số người tham gia vượt quá 100 người nên chúng tôi quyết định thuê hội trường lớn.", count: 0 },
                    { gramType: "quiz", q: "原材料の仕入れから商品ができるまでの（___________）を図にしてみました。", ans: "過程", w1: "過去", w2: "過激", w3: "過剰", explain: "過程（かてい）: quá trình\n過去（かこ）: quá khứ\n過激（かげき）: quá khích\n過剰（かじょう）: dư thừa\nDịch: Tôi đã vẽ sơ đồ quá trình từ nhập nguyên liệu đến khi sản phẩm hoàn thành.", count: 0 },
                    { gramType: "quiz", q: "ホームページで、弊社の商品を（___________）別に分類してご紹介しております。", ans: "カテゴリー", w1: "カタログ", w2: "カレンダー", w3: "カルシウム", explain: "カテゴリー: danh mục\nカタログ: catalogue\nカレンダー: lịch\nカルシウム: canxi\nDịch: Trên website, chúng tôi giới thiệu sản phẩm được phân loại theo từng danh mục.", count: 0 },
                    { gramType: "quiz", q: "来月1日より、いよいよ弊社の新工場が（___________）し始めることになりました。", ans: "稼働", w1: "可動", w2: "稼動", w3: "作動", explain: "稼働（かどう）: vận hành, đi vào hoạt động\n可動（かどう）: có thể vận hành\n稼動（かどう）: hoạt động (cách viết cũ)\n作動（さどう）: hoạt động máy móc\nDịch: Từ ngày 1 tháng sau, nhà máy mới của công ty chúng tôi cuối cùng cũng sẽ bắt đầu đi vào hoạt động.", count: 0 }
